const greetings = [
  'Xin chào ! Mình là trợ lý ảo của Anrealshop. Mình có thể giúp bạn tìm kiếm sản phẩm thời trang, tư vấn style, hoặc trả lời các thắc mắc về shop. Bạn cần hỗ trợ gì ?',
  'Chào bạn ! Rất vui được gặp bạn tại Anrealshop. Mình sẵn sàng giúp bạn tìm kiếm áo, quần, giày dép hoặc phụ kiện. Bạn muốn xem gì hôm nay ?',
  'Hello! Chào mừng bạn đến Anrealshop. Mình có thể giúp bạn tìm các sản phẩm bán chạy, hàng mới về, hoặc sản phẩm đang sale. Hãy hỏi mình nhé!'
];

const randomGreeting = greetings[Math.floor(Math.random() * greetings.length)];

return {
  json: {
    message: randomGreeting,
    type: "Greeting"
  }
};

const message = `Xin lỗi bạn, Anrealshop là shop chuyên về thời trang nên mình không thể hỗ trợ câu hỏi này.

Mình có thể giúp bạn với các vấn đề như:
- Tìm kiếm sản phẩm (áo, quần, giày, phụ kiện...)
- Xem sản phẩm bán chạy, hàng mới về
- Tìm sản phẩm theo giá, theo danh mục
- Xem đánh giá sản phẩm
- Các chương trình khuyến mãi, sale

Bạn có muốn mình giúp gì khác không?`;

return {
  json: {
    message: message,
    type: "NotFashion"
  }
};

const results = $input.all();
const classifierOutput = $('AI Agent Classifier').first().json.output;
const queryType = classifierOutput.query_type || 'unknown';
const userIntent = classifierOutput.intent || '';

if (!results || results.length === 0) {
  return {
    json: {
      data: JSON.stringify({
        error: true,
        message: "Dạ, Anrealshop hiện chưa tìm thấy thông tin phù hợp với yêu cầu của mình ạ.",
        items: []
      })
    }
  };
}

// Chuyển đổi và xử lý logic giá/ảnh từ DB mới
const processedItems = results.map(item => {
  const data = item.json;

  // Tính toán giá hiển thị dựa trên schema mới 
  const currentPrice = (data.gia_giam && data.gia_giam > 0) ? data.gia_giam : data.gia_goc;
  const discountPercent = data.gia_giam > 0 ? Math.round((1 - data.gia_giam / data.gia_goc) * 100) : 0;

  return {
    id: data.id_san_pham || data.id_cua_hang || data.id_danh_muc,
    name: data.ten_san_pham || data.ten_cua_hang || data.ten_danh_muc,
    price: currentPrice,
    original_price: data.gia_goc,
    discount: discountPercent,
    rating: data.diem_danh_giatb ? parseFloat(data.diem_danh_giatb).toFixed(1) : 0,
    total_reviews: data.tong_danh_gia || 0,
    sold: data.da_ban || 0,
    thumbnail: data.anh_dai_dien,
    shop_name: data.ten_cua_hang,
    category_name: data.ten_danh_muc,
    description: data.mo_ta_ngan || data.mo_ta
  };
});

return {
  json: {
    data: JSON.stringify({
      error: false,
      queryType: queryType,
      intent: userIntent,
      items: processedItems
    })
  }
};

// 1. Lấy dữ liệu thô đã được chuẩn hóa từ node "Format data"
let inputData = { items: [] };
try {
  const rawData = $('Format data').first().json.data;
  inputData = typeof rawData === 'string' ? JSON.parse(rawData) : rawData;
} catch (e) {
  console.error("Lỗi parse inputData:", e);
}

// 2. Lấy nội dung tin nhắn từ AI Agent Format (Xử lý đa luồng output)
const aiOutput = $input.first().json;
let message = aiOutput.output?.message || aiOutput.output || aiOutput.text || aiOutput.message || "";

// 3. Logic dự phòng (Fallback) nếu AI không trả về message
if (!message || message.trim() === '') {
  if (inputData.items && inputData.items.length > 0) {
    message = `Dạ, Anrealshop tìm thấy ${inputData.items.length} kết quả phù hợp:\n\n`;
    inputData.items.forEach((item, idx) => {
      const formattedPrice = new Intl.NumberFormat('vi-VN').format(item.price) + 'đ';
      message += `${idx + 1}. ${item.name}\n`;
      message += `   - Giá: ${formattedPrice}\n`;
      if (item.rating > 0) {
        message += `   - Đánh giá: ${item.rating}/5 (${item.total_reviews} lượt)\n`;
      }
      if (item.thumbnail) message += `   [IMAGE:${item.thumbnail}]\n`;
      message += '\n';
    });
  } else {
    message = "Dạ, hiện tại em chưa tìm thấy thông tin phù hợp. Anh/Chị có thể thử lại với từ khóa khác không ạ?";
  }
}

// 4. Trích xuất danh sách URL hình ảnh từ Tag [IMAGE:url]
const imageTagRegex = /\[IMAGE:(https?:\/\/[^\]\s]+)\]/gi;
let imageUrls = [];
let match;

while ((match = imageTagRegex.exec(message)) !== null) {
  imageUrls.push(match[1]);
}

// 5. Nếu trong text không có tag, lấy từ dữ liệu thumbnail của item đầu tiên làm dự phòng
if (imageUrls.length === 0 && inputData.items?.[0]?.thumbnail) {
  imageUrls.push(inputData.items[0].thumbnail);
}

// 6. Làm sạch tin nhắn (Tùy chọn: Giữ tag IMAGE nếu Frontend tự xử lý, hoặc xóa bỏ để tránh rác text)
// Ở đây chúng ta giữ nguyên để FE nhận biết vị trí ảnh, hoặc xóa tag nếu chỉ muốn gửi text thuần.
// message = message.replace(imageTagRegex, "").trim(); 

return {
  json: {
    message: message,
    type: inputData.error ? "Error" : "Normal",
    queryType: inputData.queryType,
    imageUrl: imageUrls[0] || null, // Ảnh chính
    imageUrls: imageUrls.slice(0, 5) // Danh sách tối đa 5 ảnh
  }
};
